import{_ as t,o as s,c as o,a2 as a}from"./chunks/framework.BWuWLRhz.js";const p=JSON.parse('{"title":"RFC 0019 — Test setup & seeding","description":"","frontmatter":{},"headers":[],"relativePath":"rfcs/0019-test-setup-and-seeding.md","filePath":"rfcs/0019-test-setup-and-seeding.md"}'),n={name:"rfcs/0019-test-setup-and-seeding.md"};function r(d,e,i,c,l,h){return s(),o("div",null,[...e[0]||(e[0]=[a('<h1 id="rfc-0019-—-test-setup-seeding" tabindex="-1">RFC 0019 — Test setup &amp; seeding <a class="header-anchor" href="#rfc-0019-—-test-setup-seeding" aria-label="Permalink to &quot;RFC 0019 — Test setup &amp; seeding&quot;">​</a></h1><p><strong>Status:</strong> Accepted<br><strong>Date:</strong> June 2026<br><strong>Author:</strong> kasunben<br><strong>Scope:</strong> <code>packages/db</code> (test-DB helpers + seed), <code>apps/auth</code> (seed users via better-auth), a seed entrypoint (<code>scripts/seed.ts</code> / <code>sv seed</code> in <code>bin/sv</code>), in-code fixtures/factories, <code>vitest.config.ts</code>, <code>CONTRIBUTING.md</code> + CLAUDE.md test docs; builds on RFC 0010 (test organization)<br><strong>Incorporated into plan:</strong> Yes — scheduled as roadmap Task 0.5.24; documentation-first. This RFC specifies a test-data foundation (fixtures, an idempotent seed, per-role test users) and the dev/prod mode concept; SRS requirement IDs, scheduling, and task allocation are deferred. <strong>Testing on a production instance is a separate RFC 0020</strong> that builds on the seed defined here.</p><hr><h2 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h2><p>Give Sovereign a real test-data foundation so developers stop recreating users and data by hand every run, and so integration/e2e tests have known principals to act as. Two pieces:</p><ul><li><strong>In-code fixtures / factories</strong> for unit and integration tests (build a user, tenant, plugin-state, notification — no running instance, no DB).</li><li><strong>An idempotent seed</strong> (<code>sv seed</code>) that populates a <strong>dev/test database</strong> with baseline data and <strong>test users per role</strong> (admin, regular user; extensible), with known credentials, so you can log in as any role immediately and re-seed anytime.</li></ul><p>It also names the <strong>dev vs prod mode</strong> distinction that RFC 0020 builds on: dev is the default locally; seeding is a dev-mode-only capability, <strong>hard-gated so it can never run against a real production database.</strong></p><h2 id="motivation" tabindex="-1">Motivation <a class="header-anchor" href="#motivation" aria-label="Permalink to &quot;Motivation&quot;">​</a></h2><p>There is <strong>no test-data infrastructure today</strong> — no fixtures, factories, seeding, or test users anywhere in the tree. Every developer manually registers a first (admin) user, then more users, sets roles, and rebuilds data on each fresh database. Integration and (future) e2e tests have no known accounts to drive. This is friction for contributors and a blocker for the e2e tier RFC 0010 reserves.</p><h2 id="current-state-what-this-builds-on" tabindex="-1">Current state (what this builds on) <a class="header-anchor" href="#current-state-what-this-builds-on" aria-label="Permalink to &quot;Current state (what this builds on)&quot;">​</a></h2><ul><li><strong>Vitest, no fixtures.</strong> <code>vitest.config.ts</code> runs co-located <code>*.test.ts(x)</code> in the <code>node</code> environment (jsdom via pragma); <code>pnpm test</code> = <code>vitest run</code>. There are <strong>no fixture factories, no seed scripts, and no test users</strong> — tests build any needed data inline.</li><li><strong>DB in tests.</strong> The default suite uses <strong>in-memory SQLite</strong> (<code>createClient({ url: &#39;:memory:&#39; })</code> + <code>bootstrapPlatformDb</code>); the Postgres <strong>parity</strong> tests (<code>*.pg.test.ts</code>) are gated by <code>TEST_DATABASE_URL</code> and <strong>drop/recreate</strong> their tables in <code>beforeAll</code>. CI starts a throwaway Postgres and sets <code>TEST_DATABASE_URL</code>.</li><li><strong>User archetypes already exist as states.</strong> <code>apps/auth/src/auth.ts</code> assigns the <strong>first user</strong> <code>platform:admin</code> (rest <code>platform:user</code>), with an <code>active</code> flag (deactivated) and an <code>invites</code> table (invited-pending) — i.e. admin / regular / deactivated / invited. The admin-key API (<code>apps/auth/app/api/admin/*</code>) can create invites and change role/active programmatically.</li><li><strong>Idempotent bootstrap pattern.</strong> <code>packages/db/src/platform-db.ts</code> (<code>bootstrapPlatformDb</code>) seeds the default tenant + <code>root_plugin_id</code> with <code>ON CONFLICT … DO NOTHING</code> — the proven model for a safe, re-runnable seed.</li><li><strong>Password hashing.</strong> better-auth uses Argon2id; <code>better-auth/crypto</code>&#39;s <code>hashPassword</code> lets a seed insert a user with a <strong>known</strong> password directly.</li><li><strong>RFC 0010</strong> reserves the e2e/integration tiers (Task 0.5.17, not yet run); this RFC&#39;s data foundation feeds them.</li></ul><h2 id="dev-vs-prod-mode-shared-concept" tabindex="-1">Dev vs prod mode (shared concept) <a class="header-anchor" href="#dev-vs-prod-mode-shared-concept" aria-label="Permalink to &quot;Dev vs prod mode (shared concept)&quot;">​</a></h2><p>Sovereign runs in one of two modes:</p><ul><li><strong>Dev mode</strong> — the default locally (<code>NODE_ENV !== &#39;production&#39;</code>). Seeding and relaxed diagnostics are dev-mode features.</li><li><strong>Prod mode</strong> — the shipped default for a real deployment.</li></ul><p>This RFC introduces the distinction and the dev-only seed; <strong>RFC 0020</strong> extends it with a way to toggle a <em>prod</em> instance into dev-mode against a mock database.</p><h2 id="proposed-design" tabindex="-1">Proposed design <a class="header-anchor" href="#proposed-design" aria-label="Permalink to &quot;Proposed design&quot;">​</a></h2><h3 id="idempotent-seed-sv-seed" tabindex="-1">Idempotent seed (<code>sv seed</code>) <a class="header-anchor" href="#idempotent-seed-sv-seed" aria-label="Permalink to &quot;Idempotent seed (`sv seed`)&quot;">​</a></h3><p>A seed entrypoint — <code>sv seed</code> (delegating to <code>scripts/seed.ts</code>) — populates a <strong>dev/test database</strong> with:</p><ul><li>baseline platform data (reusing <code>bootstrapPlatformDb</code>);</li><li><strong>test users per role</strong> — at minimum an <strong>admin</strong> and a <strong>regular user</strong>, with documented emails and known dev passwords (e.g. <code>admin@dev.local</code> / <code>user@dev.local</code>). Extensible later to deactivated/invited archetypes.</li></ul><p>Properties:</p><ul><li><strong>Idempotent</strong> — <code>ON CONFLICT … DO NOTHING</code> / exists-checks, safe to re-run; a developer runs it once and re-runs anytime without duplicates.</li><li><strong>Known passwords</strong> — inserted via <code>better-auth/crypto</code> <code>hashPassword</code>, so the seeded users can actually log in (faster and more deterministic than driving the registration flow).</li><li><strong>Hard-gated to non-prod</strong> — the seed <strong>refuses to run</strong> against a production database / in prod mode unless an explicit override is set. It must be impossible to accidentally seed fake users into a real instance. (RFC 0020 is the sanctioned way to use seeded mock data <em>on</em> a prod deployment — against a separate mock DB, never the real one.)</li></ul><h3 id="fixtures-factories" tabindex="-1">Fixtures / factories <a class="header-anchor" href="#fixtures-factories" aria-label="Permalink to &quot;Fixtures / factories&quot;">​</a></h3><p>In-code builders for <strong>unit and integration</strong> tests — <code>makeUser()</code>, <code>makeTenant()</code>, <code>makePluginStatus()</code>, <code>makeNotification()</code>, etc. — that return plain objects/rows with sensible defaults and overrides, with <strong>no running instance and no DB</strong>. Placed per RFC 0010 (per-package <code>__tests__/</code> for package-local fixtures; the cross-boundary root <code>/__tests__/</code> for shared ones). These complement the seed: fixtures for fast in-process tests, the seed for a running instance (dev + e2e).</p><h3 id="test-database-story" tabindex="-1">Test database story <a class="header-anchor" href="#test-database-story" aria-label="Permalink to &quot;Test database story&quot;">​</a></h3><p>No new mechanism is needed to <em>select</em> a test DB — <code>DATABASE_URL</code> / <code>AUTH_DATABASE_URL</code> already switch databases (and dialect via <code>DB_DIALECT</code>), config-only. This RFC adds:</p><ul><li>the documented, <strong>disposable dev/test DB</strong> the seeder targets;</li><li>continuity with the existing env-gated pg parity pattern (unchanged);</li><li>the note that <strong>this same dev/test DB becomes RFC 0020&#39;s mock database</strong> when a prod instance is toggled into dev-mode.</li></ul><h3 id="e2e-tier-alignment-rfc-0010" tabindex="-1">e2e tier alignment (RFC 0010) <a class="header-anchor" href="#e2e-tier-alignment-rfc-0010" aria-label="Permalink to &quot;e2e tier alignment (RFC 0010)&quot;">​</a></h3><p>The reserved e2e tier (Playwright, Task 0.5.17) consumes a <strong>seeded</strong> instance: it logs in as the documented test users and drives real flows. This RFC supplies the users/credentials; the harness itself lands with RFC 0010&#39;s task.</p><h2 id="ui-flows" tabindex="-1">UI / flows <a class="header-anchor" href="#ui-flows" aria-label="Permalink to &quot;UI / flows&quot;">​</a></h2><p><strong>Local dev</strong> — <code>sv seed</code> once → log in as <code>admin@dev.local</code> or <code>user@dev.local</code> with the documented password → build features → re-run <code>sv seed</code> anytime (idempotent) to restore baseline data without losing your DB.</p><p><strong>CI / e2e</strong> — a job seeds an ephemeral DB, then runs integration/e2e against it with the known accounts.</p><h2 id="alternatives-considered" tabindex="-1">Alternatives considered <a class="header-anchor" href="#alternatives-considered" aria-label="Permalink to &quot;Alternatives considered&quot;">​</a></h2><ol><li><strong>Inline per-test data only (status quo).</strong> Rejected — repetitive, no shared archetypes, and nothing for a running instance / e2e to use.</li><li><strong>Seed exclusively through the public registration/invite flow.</strong> Slower and ordering-sensitive (first-user-admin, invite gating). Kept as an option for tests that specifically exercise those flows, but the default seed uses direct hashed inserts for speed and determinism.</li><li><strong>Ship test users in the bootstrap (always).</strong> Rejected — bootstrap runs in prod; test users must be dev-only and explicitly seeded, never present by default.</li></ol><h2 id="open-questions" tabindex="-1">Open questions <a class="header-anchor" href="#open-questions" aria-label="Permalink to &quot;Open questions&quot;">​</a></h2><ol><li><strong>Seed entrypoint</strong> — <code>sv seed</code> vs <code>pnpm seed</code> vs a dev-only instrumentation hook that seeds on first dev boot.</li><li><strong>How many archetypes now</strong> — admin + user is enough for v1; when to add deactivated/invited (and per-plugin sample data).</li><li><strong>Per-test isolation</strong> — fresh <code>:memory:</code> per file (today) vs transaction rollback per test for the integration tier.</li><li><strong>Requirement IDs</strong> — proposed entries, deferred until accepted.</li></ol><h2 id="adoption-path" tabindex="-1">Adoption path <a class="header-anchor" href="#adoption-path" aria-label="Permalink to &quot;Adoption path&quot;">​</a></h2><ol><li><strong>Documentation-first (this RFC).</strong></li><li><strong>When accepted &amp; scheduled:</strong> the fixtures/factories, the <code>sv seed</code> entrypoint + per-role test users (non-prod-gated), the documented dev/test DB, and the CONTRIBUTING/CLAUDE.md test docs — aligned with RFC 0010&#39;s layout. The e2e harness follows with RFC 0010 (Task 0.5.17). RFC 0020 then reuses this seed for prod dev-mode.</li></ol><h2 id="changelog" tabindex="-1">Changelog <a class="header-anchor" href="#changelog" aria-label="Permalink to &quot;Changelog&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Version</th><th>Date</th><th>Change</th></tr></thead><tbody><tr><td>0.1</td><td>Jun 2026</td><td>Initial draft; in-code fixtures/factories + an idempotent <code>sv seed</code> with per-role test users (non-prod-gated), the dev/prod mode concept, and the dev/test DB that RFC 0020 reuses; documentation-first.</td></tr><tr><td>0.2</td><td>Jun 2026</td><td>Accepted; scheduled in the roadmap as Task 0.5.24.</td></tr></tbody></table>',39)])])}const g=t(n,[["render",r]]);export{p as __pageData,g as default};
